mapper.delete:
/* com.educare.edu.comn.mapper.FeedbackAnswerMapper.deleteByFbIdxUserId */
	delete from t_feedback_answer
	where edu_seq=#{eduSeq} and fe_seq=#{feSeq} and fb_idx=#{fbIdx} and user_id=#{userId}

mapper.select:
/* com.educare.edu.comn.mapper.FeedbackAnswerMapper.selectBy_FbIdx_QtIdx_UserIdx */
select * from t_feedback_answer
where edu_seq=#{eduSeq} and fe_seq=#{feSeq} and fb_idx=#{fbIdx} and qt_idx=#{qtIdx} and user_id=#{userId}
